132	    use vunit_lib.stream_master_pkg.all;
133	    use vunit_lib.sync_pkg.all;
134	
135	library osvvm;
136	    use osvvm.randompkg.all;
137	
138	library work;
139	    use work.olo_test_fix_checker_pkg.all;
140	
141	library olo;
142	    use olo.en_cl_fix_pkg.all;
143	    use olo.olo_fix_pkg.all;
144	
145	entity olo_test_fix_checker_vc is
146	    generic (
147	        instance                 : olo_test_fix_checker_t;
148	        is_timing_master         : boolean := true;
149	        fmt                      : FixFormat_t
150	    );
151	    port (
152	        clk      : in    std_logic;
153	        ready    : inout std_logic; -- input for slave, output for master
154	        valid    : in    std_logic;
155	        last     : in    std_logic := '0';
156	        data     : in    std_logic_vector(cl_fix_width(fmt)-1 downto 0)
157	    );
158	end entity;
159	
160	architecture a of olo_test_fix_checker_vc is
161	
162	    -- Declarations
163	    shared variable random_v : RandomPType;
164	
165	begin
166	
167	    -- Main Process
168	    main : process is
169	        -- Messaging
170	        variable request_msg       : msg_t;
171	        variable msg_type          : msg_type_t;
172	        variable msg_p             : string_ptr_t;
173	        variable file_path_p       : string_ptr_t;
174	        variable mode              : olo_fix_checker_mode_t;
175	        variable tdm_slots         : positive;
176	        variable stall_probability : real;
177	        variable stall_max_cycles  : positive;
178	        variable stall_min_cycles  : positive;
179	
180	        -- File
181	        file data_file : text;
182	
183	        variable data_slv      : std_logic_vector(cl_fix_width(fmt)-1 downto 0);
184	        variable next_data_slv : std_logic_vector(cl_fix_width(fmt)-1 downto 0);
185	        variable has_data      : boolean;
186	        variable next_has_data : boolean;
187	
188	        -- Others
189	        variable stall_random : real;
190	        variable stall_cycles : positive;
191	        variable line_number  : positive;
192	        variable slot_cnt     : natural;
193	        variable is_last      : boolean;
194	        variable last_check   : std_logic;
195	    begin
196	
197	        -- Initialize
198	        if is_timing_master then
199	            ready <= '0';
200	        else
201	            ready <= 'Z';
202	        end if;
203	        random_v.InitSeed(random_v'instance_name);
204	
205	        -- Loop though messages
206	        loop
207	            -- Receive message
208	            receive(net, instance.p_actor, request_msg);
209	            msg_type := message_type(request_msg);
210	
211	            -- *** Handle Messages ***
212	            if msg_type = fix_checker_check_file_msg then
213	                -- Pop Transaction
214	                file_path_p       := new_string_ptr(pop_string(request_msg));
215	                mode              := olo_fix_checker_mode_t'val(integer'(pop(request_msg)));
216	                tdm_slots         := pop(request_msg);
217	                stall_probability := pop(request_msg);
218	                stall_max_cycles  := pop(request_msg);
219	                stall_min_cycles  := pop(request_msg);
220	                msg_p             := new_string_ptr(pop_string(request_msg));
221	
222	                -- Open file and check format (first line)
223	                file_open(data_file, to_string(file_path_p), read_mode);
224	                fixFileCheckHeader(data_file, fmt);
225	                line_number := 2;
226	
227	                -- Read first data line
228	                if not endfile(data_file) then
229	                    data_slv := fixFileReadSample(data_file, fmt);
230	                    has_data := true;
231	                else
232	                    has_data := false;
233	                end if;
234	
235	                slot_cnt := 0;
236	
237	                -- Iterate through lines in file
238	                while has_data loop
239	                    -- Try read next line
240	                    if not endfile(data_file) then
241	                        next_data_slv := fixFileReadSample(data_file, fmt);
242	                        next_has_data := true;
243	                    else
244	                        next_has_data := false;
245	                    end if;
246	
247	                    -- Determine Last
248	                    is_last := false;
249	                    if mode = checker_mode_packet and not next_has_data then
250	                        is_last := true;
251	                    elsif mode = checker_mode_tdm and slot_cnt = tdm_slots - 1 then
252	                        is_last := true;
253	                    end if;
254	                    if is_last then
255	                        last_check := '1';
256	                    else
257	                        last_check := '0';
258	                    end if;
259	
260	                    -- Update slot counter
261	                    if slot_cnt = tdm_slots - 1 then
262	                        slot_cnt := 0;
263	                    else
264	                        slot_cnt := slot_cnt + 1;
265	                    end if;
266	
267	                    -- Wait for ready signal if timing master
268	                    if is_timing_master then
269	                        -- Stall
270	                        stall_random := random_v.RandReal(0.0, 1.0);
271	                        if stall_random < stall_probability then
272	                            ready <= '0';
273	
274	                            -- Wait for stall
275	                            stall_cycles := random_v.RandInt(stall_min_cycles, stall_max_cycles);
276	
277	                            for i in 0 to stall_cycles - 1 loop
278	                                wait until rising_edge(clk) and valid = '1';
279	                            end loop;
280	
281	                            wait until falling_edge(clk);
282	                        end if;
283	                        ready <= '1';
284	                        wait until rising_edge(clk) and valid = '1';
285	                    else
286	                        wait until rising_edge(clk) and ready = '1' and valid = '1';
287	                    end if;
288	
289	                    -- Apply Data
290	                    check_equal(data, data_slv, "olo_test_fix - " & to_string(msg_p) &
291	                                                " - file " & to_string(file_path_p) &
292	                                                " - line " & to_string(line_number));
293	
294	                    -- Check Last
295	                    if mode = checker_mode_tdm then
296	                        check_equal(last, last_check, "olo_test_fix - " & to_string(msg_p) &
297	                                                      " - Last Mismatch in TDM slot " & to_string(slot_cnt) &
298	                                                      " - file " & to_string(file_path_p) &
299	                                                      " - line " & to_string(line_number));
300	                    elsif mode = checker_mode_packet then
301	                        if last = '1' then
302	                            check_equal(last, last_check, "olo_test_fix - " & to_string(msg_p) &
303	                                                          " - Last Asserted Early - file " & to_string(file_path_p) &
304	                                                          " - line " & to_string(line_number));
305	                        else
306	                            check_equal(last, last_check, "olo_test_fix - " & to_string(msg_p) &
307	                                                          " - Last Missing - file " & to_string(file_path_p) &
308	                                                          " - line " & to_string(line_number));
309	                        end if;
310	                    end if;
311	
312	                    line_number := line_number + 1;
313	
314	                    -- Move next to current
315	                    data_slv := next_data_slv;
316	                    has_data := next_has_data;
317	                end loop;
318	
319	                -- Close the file
320	                file_close(data_file);
321	
322	                -- Idle output
323	                if is_timing_master then
324	                    ready <= '0';
325	                end if;
326	
327	            elsif msg_type = wait_until_idle_msg then
328	                handle_wait_until_idle(net, msg_type, request_msg);
329	            else
330	                unexpected_msg_type(msg_type);
331	            end if;
332	        end loop;
333	
334	    end process;
335	
336	end architecture;
