162	    procedure push_aw (
163	        signal net : inout network_t;
164	        axi_master : olo_test_axi_master_t;
165	        addr       : unsigned;
166	        id         : std_logic_vector := "X";
167	        len        : positive         := 1;
168	        burst      : Burst_t          := AxiBurst_Incr_c;
