177	        end if;
178	        -- implementation
179	        push(msg, resize(addr, axi_master.addr_width));
180	        push(msg, id_v);
181	        push(msg, len);
182	        push(msg, burst);
183	        push(msg, delay);
184	        send(net, axi_master.p_actor, msg);
185	    end procedure;
