203	        end if;
204	        -- implementation
205	        push(msg, resize(addr, axi_master.addr_width));
206	        push(msg, id_v);
207	        push(msg, len);
208	        push(msg, burst);
209	        push(msg, delay);
210	        send(net, axi_master.p_actor, msg);
211	    end procedure;
