236	        -- implementation
237	        push(msg, resize(start_value, axi_master.data_width));
238	        push(msg, increment);
239	        push(msg, beats);
240	        push(msg, frst_strb_v);
241	        push(msg, last_strb_v);
242	        push(msg, delay);
243	        send(net, axi_master.p_actor, msg);
244	    end procedure;
