425	
426	architecture a of olo_test_axi_master_vc is
427	
428	    -- Aw State
429	    constant aw_queue            : queue_t := new_queue;
430	    shared variable aw_initiated : natural := 0;
431	    shared variable aw_completed : natural := 0;
432	
433	    -- Ar State
434	    constant ar_queue            : queue_t := new_queue;
435	    shared variable ar_initiated : natural := 0;
436	    shared variable ar_completed : natural := 0;
437	
438	    -- W State
439	    constant w_queue            : queue_t := new_queue;
440	    shared variable w_initiated : natural := 0;
441	    shared variable w_completed : natural := 0;
442	
443	    -- B State
444	    constant b_queue            : queue_t := new_queue;
445	    shared variable b_initiated : natural := 0;
446	    shared variable b_completed : natural := 0;
447	
448	    -- R State
449	    constant r_queue            : queue_t := new_queue;
450	    shared variable r_initiated : natural := 0;
451	    shared variable r_completed : natural := 0;
452	
453	begin
454	
455	    -- Main process
456	    main : process is
457	        variable request_msg : msg_t;
458	        variable copy_msg    : msg_t;
459	        variable msg_type    : msg_type_t;
460	    begin
461	
462	        -- Loop though messages
463	        loop
464	            -- Receive message
465	            receive(net, instance.p_actor, request_msg);
466	            msg_type := message_type(request_msg);
467	            copy_msg := copy(request_msg);
468	            -- Handle Message
469	            if msg_type = axi_aw_msg then
470	                -- AW
471	                push(aw_queue, copy_msg);
472	                aw_initiated := aw_initiated + 1;
473	            elsif msg_type = axi_ar_msg then
474	                -- AR
475	                push(ar_queue, copy_msg);
476	                ar_initiated := ar_initiated + 1;
477	            elsif msg_type = axi_w_msg then
478	                -- W
479	                push(w_queue, copy_msg);
480	                w_initiated := w_initiated + 1;
481	            elsif msg_type = axi_b_msg then
482	                -- B
483	                push(b_queue, copy_msg);
484	                b_initiated := b_initiated + 1;
485	            elsif msg_type = axi_r_msg then
486	                -- R
487	                push(r_queue, copy_msg);
488	                r_initiated := r_initiated + 1;
489	            elsif msg_type = wait_until_idle_msg then
490	
491	                -- Wait until idle
492	                while aw_initiated /= aw_completed or
493	                      ar_initiated /= ar_completed or
494	                      w_initiated /= w_completed or
495	                      b_initiated /= b_completed or
496	                      r_initiated /= r_completed loop
497	                    wait until rising_edge(clk);
498	                end loop;
499	
500	                handle_wait_until_idle(net, msg_type, request_msg);
501	            else
502	                delete(copy_msg);
503	                unexpected_msg_type(msg_type);
504	            end if;
505	        end loop;
506	
507	        wait;
508	    end process;
509	
510	    -- AW process
511	    p_aw : process is
512	        variable msg      : msg_t;
513	        variable msg_type : msg_type_t;
514	        variable addr     : unsigned(instance.addr_width-1 downto 0);
515	        variable id       : std_logic_vector(instance.id_width-1 downto 0);
516	        variable len      : positive;
517	        variable burst    : Burst_t;
518	        variable delay    : time;
519	    begin
520	        -- Initialize
521	        axi_ms.aw_id     <= toUslv(0, axi_ms.aw_id'length);
522	        axi_ms.aw_addr   <= toUslv(0, axi_ms.aw_addr'length);
523	        axi_ms.aw_len    <= toUslv(0, 8);
524	        axi_ms.aw_size   <= toUslv(0, 3);
525	        axi_ms.aw_burst  <= "01";
526	        axi_ms.aw_valid  <= '0';
527	        axi_ms.aw_lock   <= '0';
528	        axi_ms.aw_cache  <= toUslv(0, 4);
529	        axi_ms.aw_prot   <= toUslv(0, 3);
530	        axi_ms.aw_qos    <= toUslv(0, 4);
531	        axi_ms.aw_region <= toUslv(0, 4);
532	        axi_ms.aw_user   <= toUslv(0, axi_ms.aw_user'length);
533	        wait until rising_edge(clk);
534	
535	        -- loop messages
536	        loop
537	            -- wait until message available
538	            if is_empty(aw_queue) then
539	                wait until not is_empty(aw_queue) and rising_edge(clk);
540	            end if;
541	            -- get message
542	            msg      := pop(aw_queue);
543	            msg_type := message_type(msg);
544	            -- process message
545	            if msg_type = axi_aw_msg then
546	                -- Pop Information
547	                addr  := pop(msg);
548	                id    := pop(msg);
549	                len   := pop(msg);
550	                burst := pop(msg);
551	                delay := pop(msg);
552	                -- Execute
553	                if delay > 0 ns then
554	                    wait for delay;
555	                    wait until rising_edge(clk);
556	                end if;
557	                axi_ms.aw_id    <= id;
558	                axi_ms.aw_addr  <= std_logic_vector(addr);
559	                axi_ms.aw_len   <= toUslv(len-1, 8);
560	                axi_ms.aw_size  <= toUslv(log2(instance.data_width/8), 3);
561	                axi_ms.aw_burst <= burst;
562	                axi_ms.aw_valid <= '1';
563	                wait until rising_edge(clk) and axi_sm.aw_ready = '1';
564	                axi_ms.aw_valid <= '0';
565	                axi_ms.aw_id    <= toUslv(0, axi_ms.aw_id'length);
566	                axi_ms.aw_addr  <= toUslv(0, axi_ms.aw_addr'length);
567	                axi_ms.aw_len   <= toUslv(0, 8);
568	                axi_ms.aw_size  <= toUslv(0, 3);
569	                axi_ms.aw_burst <= AxiBurst_Incr_c;
570	                aw_completed    := aw_completed + 1;
571	            else
572	                unexpected_msg_type(msg_type);
573	            end if;
574	            delete(msg);
575	        end loop;
576	
577	        wait;
578	    end process;
579	
580	    -- AR process
581	    p_ar : process is
582	        variable msg      : msg_t;
583	        variable msg_type : msg_type_t;
584	        variable addr     : unsigned(instance.addr_width-1 downto 0);
585	        variable id       : std_logic_vector(instance.id_width-1 downto 0);
586	        variable len      : positive;
587	        variable burst    : Burst_t;
588	        variable delay    : time;
589	    begin
590	        -- Initialize
591	        axi_ms.ar_id     <= toUslv(0, axi_ms.ar_id'length);
592	        axi_ms.ar_addr   <= toUslv(0, axi_ms.ar_addr'length);
593	        axi_ms.ar_len    <= toUslv(0, 8);
594	        axi_ms.ar_size   <= toUslv(0, 3);
595	        axi_ms.ar_burst  <= "01";
596	        axi_ms.ar_valid  <= '0';
597	        axi_ms.ar_lock   <= '0';
598	        axi_ms.ar_cache  <= toUslv(0, 4);
599	        axi_ms.ar_prot   <= toUslv(0, 3);
600	        axi_ms.ar_qos    <= toUslv(0, 4);
601	        axi_ms.ar_region <= toUslv(0, 4);
602	        axi_ms.ar_user   <= toUslv(0, axi_ms.ar_user'length);
603	        wait until rising_edge(clk);
604	
605	        -- loop messages
606	        loop
607	            -- wait until message available
608	            if is_empty(ar_queue) then
609	                wait until not is_empty(ar_queue) and rising_edge(clk);
610	            end if;
611	            -- get message
612	            msg      := pop(ar_queue);
613	            msg_type := message_type(msg);
614	            -- process message
615	            if msg_type = axi_ar_msg then
616	                -- Pop Information
617	                addr  := pop(msg);
618	                id    := pop(msg);
619	                len   := pop(msg);
620	                burst := pop(msg);
621	                delay := pop(msg);
622	                -- Execute
623	                if delay > 0 ns then
624	                    wait for delay;
625	                    wait until rising_edge(clk);
626	                end if;
627	                axi_ms.ar_id    <= id;
628	                axi_ms.ar_addr  <= std_logic_vector(addr);
629	                axi_ms.ar_len   <= toUslv(len-1, 8);
630	                axi_ms.ar_size  <= toUslv(log2(instance.data_width/8), 3);
631	                axi_ms.ar_burst <= burst;
632	                axi_ms.ar_valid <= '1';
633	                wait until rising_edge(clk) and axi_sm.ar_ready = '1';
634	                axi_ms.ar_valid <= '0';
635	                axi_ms.ar_id    <= toUslv(0, axi_ms.ar_id'length);
636	                axi_ms.ar_addr  <= toUslv(0, axi_ms.ar_addr'length);
637	                axi_ms.ar_len   <= toUslv(0, 8);
638	                axi_ms.ar_size  <= toUslv(0, 3);
639	                axi_ms.ar_burst <= AxiBurst_Incr_c;
640	                ar_completed    := ar_completed + 1;
641	            else
642	                unexpected_msg_type(msg_type);
643	            end if;
644	            delete(msg);
645	        end loop;
646	
647	        wait;
648	    end process;
649	
650	    -- W process
651	    p_w : process is
652	        variable msg         : msg_t;
653	        variable msg_type    : msg_type_t;
654	        variable start_value : unsigned(instance.data_width-1 downto 0);
655	        variable increment   : natural;
656	        variable beats       : natural;
657	        variable first_strb  : std_logic_vector(instance.data_width/8-1 downto 0);
658	        variable last_strb   : std_logic_vector(instance.data_width/8-1 downto 0);
659	        variable delay       : time;
660	        variable data        : unsigned(instance.data_width-1 downto 0);
661	    begin
662	        -- Initialize
663	        axi_ms.w_data  <= toUslv(0, axi_ms.w_data'length);
664	        axi_ms.w_strb  <= toUslv(0, axi_ms.w_strb'length);
665	        axi_ms.w_last  <= '0';
666	        axi_ms.w_valid <= '0';
667	        axi_ms.w_user  <= toUslv(0, axi_ms.w_user'length);
668	        wait until rising_edge(clk);
669	
670	        -- loop messages
671	        loop
672	            -- wait until message available
673	            if is_empty(w_queue) then
674	                wait until not is_empty(w_queue) and rising_edge(clk);
675	            end if;
676	            -- wait until address is sent
677	            if w_completed = aw_completed then
678	                wait until w_completed < aw_completed and rising_edge(clk);
679	            end if;
680	            -- get message
681	            msg      := pop(w_queue);
682	            msg_type := message_type(msg);
683	            -- process message
684	            if msg_type = axi_w_msg then
685	                -- Pop Information
686	                start_value := pop(msg);
687	                increment   := pop(msg);
688	                beats       := pop(msg);
689	                first_strb  := pop(msg);
690	                last_strb   := pop(msg);
691	                delay       := pop(msg);
692	                -- Execute
693	                if delay > 0 ns then
694	                    wait for delay;
695	                    wait until rising_edge(clk);
696	                end if;
697	                data := start_value;
698	
699	                -- loop through beats
700	                for i in 0 to beats-1 loop
701	                    -- Data
702	                    axi_ms.w_data <= std_logic_vector(data);
703	                    -- Strobe
704	                    if i = 0 then
705	                        axi_ms.w_strb <= first_strb;
706	                    elsif i = beats-1 then
707	                        axi_ms.w_strb <= last_strb;
708	                    else
709	                        axi_ms.w_strb <= onesVector(axi_ms.w_strb'length);
710	                    end if;
711	                    -- Last
712	                    if i = beats-1 then
713	                        axi_ms.w_last <= '1';
714	                    else
715	                        axi_ms.w_last <= '0';
716	                    end if;
717	                    -- Valid
718	                    axi_ms.w_valid <= '1';
719	                    wait until rising_edge(clk) and axi_sm.w_ready = '1';
720	                    axi_ms.w_valid <= '0';
721	                    data           := data + increment;
722	                end loop;
723	
724	                -- restore idle state
725	                axi_ms.w_data <= toUslv(0, axi_ms.w_data'length);
726	                axi_ms.w_strb <= toUslv(0, axi_ms.w_strb'length);
727	                axi_ms.w_last <= '0';
728	                w_completed   := w_completed + 1;
729	            else
730	                unexpected_msg_type(msg_type);
731	            end if;
732	            delete(msg);
733	        end loop;
734	
735	        wait;
736	    end process;
737	
738	    -- B process
739	    p_b : process is
740	        variable msg      : msg_t;
741	        variable msg_type : msg_type_t;
742	        variable resp     : Resp_t;
743	        variable id       : std_logic_vector(instance.id_width-1 downto 0);
744	        variable delay    : time;
745	    begin
746	        -- Initialize
747	        axi_ms.b_ready <= '0';
748	        wait until rising_edge(clk);
749	
750	        -- loop messages
751	        loop
752	            -- wait until message available
753	            if is_empty(b_queue) then
754	                wait until not is_empty(b_queue) and rising_edge(clk);
755	            end if;
756	            -- Wait until write is completed
757	            if b_completed = w_completed then
758	                wait until b_completed < w_completed and rising_edge(clk);
759	            end if;
760	            -- get message
761	            msg      := pop(b_queue);
762	            msg_type := message_type(msg);
763	            -- process message
764	            if msg_type = axi_b_msg then
765	                -- Pop Information
766	                resp  := pop(msg);
767	                id    := pop(msg);
768	                delay := pop(msg);
769	                -- Execute
770	                if delay > 0 ns then
771	                    wait until rising_edge(clk) and axi_sm.b_valid = '1';
772	                    wait for delay;
773	                    wait until rising_edge(clk);
774	                end if;
775	                axi_ms.b_ready <= '1';
776	                wait until rising_edge(clk) and axi_sm.b_valid = '1';
777	                check_equal(axi_sm.b_resp, resp, "expect_b: b_resp not as expected");
778	                if id /= "X" then
779	                    check_equal(axi_sm.b_id, id, "expect_b: b_id not as expected");
780	                end if;
781	                axi_ms.b_ready <= '0';
782	                b_completed    := b_completed + 1;
783	            else
784	                unexpected_msg_type(msg_type);
785	            end if;
786	            delete(msg);
787	        end loop;
788	
789	        wait;
790	    end process;
791	
792	    -- R process
793	    p_r : process is
794	        variable msg         : msg_t;
795	        variable msg_type    : msg_type_t;
796	        variable start_value : unsigned(instance.data_width-1 downto 0);
797	        variable increment   : natural;
798	        variable beats       : natural;
799	        variable resp        : Resp_t;
800	        variable id          : std_logic_vector(instance.id_width-1 downto 0);
801	        variable delay       : time;
802	        variable data        : unsigned(instance.data_width-1 downto 0);
803	        variable ignore_data : boolean;
804	    begin
805	        -- Initialize
806	        axi_ms.r_ready <= '0';
807	        wait until rising_edge(clk);
808	
809	        -- loop messages
810	        loop
811	            -- wait until message available
812	            if is_empty(r_queue) then
813	                wait until not is_empty(r_queue) and rising_edge(clk);
814	            end if;
815	            -- wait until address is sent
816	            if r_completed = ar_completed then
817	                wait until r_completed < ar_completed and rising_edge(clk);
818	            end if;
819	            -- get message
820	            msg      := pop(r_queue);
821	            msg_type := message_type(msg);
822	            -- process message
823	            if msg_type = axi_r_msg then
824	                -- Pop Information
825	                start_value := pop(msg);
826	                increment   := pop(msg);
827	                beats       := pop(msg);
828	                resp        := pop(msg);
829	                id          := pop(msg);
830	                delay       := pop(msg);
831	                ignore_data := pop(msg);
832	                -- Execute
833	                if delay > 0 ns then
834	                    wait until rising_edge(clk) and axi_sm.r_valid = '1';
835	                    wait for delay;
836	                    wait until rising_edge(clk);
837	                end if;
838	                axi_ms.r_ready <= '1';
839	                data           := start_value;
840	
841	                -- loop through beats
842	                for i in 0 to beats-1 loop
843	                    wait until rising_edge(clk) and axi_sm.r_valid = '1';
844	                    if not ignore_data then
845	                        check_equal(axi_sm.r_data, data, "expect_r: r_data not as expected");
846	                    end if;
847	                    check_equal(axi_sm.r_resp, resp, "expect_r: r_resp not as expected");
848	                    if id /= "X" then
849	                        check_equal(axi_sm.r_id, id, "expect_r: r_id not as expected");
850	                    end if;
851	                    data           := data + increment;
852	                    axi_ms.r_ready <= '0';
853	                    wait until rising_edge(clk);
854	                    axi_ms.r_ready <= '1';
855	                end loop;
856	
857	                axi_ms.r_ready <= '0';
858	                r_completed    := r_completed + 1;
859	            else
860	                unexpected_msg_type(msg_type);
861	            end if;
862	            delete(msg);
863	        end loop;
864	
865	        wait;
866	    end process;
867	
868	end architecture;
869	
870	---------------------------------------------------------------------------------------------------
871	-- AXI Lite Master Verification Component
872	---------------------------------------------------------------------------------------------------
873	library ieee;
874	    use ieee.std_logic_1164.all;
875	    use ieee.numeric_std.all;
876	
877	library work;
878	    use work.olo_test_axi_master_pkg.all;
879	    use work.olo_test_pkg_axi.all;
880	
881	library olo;
882	    use olo.olo_base_pkg_math.all;
883	
884	entity olo_test_axi_lite_master_vc is
885	    generic (
886	        instance                 : olo_test_axi_master_t
887	    );
888	    port (
889	        clk           : in    std_logic;
890	        axi_ms        : out   axi_ms_t;
891	        axi_sm        : in    axi_sm_t
892	    );
893	end entity;
894	
895	architecture a of olo_test_axi_lite_master_vc is
896	
897	    subtype id_range_c   is natural range instance.id_width - 1 downto 0;
898	    subtype addr_range_c is natural range instance.addr_width - 1 downto 0;
899	    subtype user_range_c is natural range instance.user_width - 1 downto 0;
900	    subtype data_range_c is natural range instance.data_width - 1 downto 0;
901	    subtype byte_range_c is natural range instance.data_width/8 - 1 downto 0;
902	
903	    signal axi_ms_i : axi_ms_t (ar_id(id_range_c), aw_id(id_range_c),
904	                                 ar_addr(addr_range_c), aw_addr(addr_range_c),
905	                                 ar_user(user_range_c), aw_user(user_range_c), w_user(user_range_c),
906	                                 w_data(data_range_c),
907	                                 w_strb(byte_range_c));
908	
909	    signal axi_sm_i : axi_sm_t (r_id(id_range_c), b_id(id_range_c),
910	                                 r_user(user_range_c), b_user(user_range_c),
911	                                 r_data(data_range_c));
912	
913	begin
914	
915	    axi_ms.ar_addr  <= axi_ms_i.ar_addr;
916	    axi_ms.ar_valid <= axi_ms_i.ar_valid;
917	    axi_ms.r_ready  <= axi_ms_i.r_ready;
918	    axi_ms.aw_addr  <= axi_ms_i.aw_addr;
919	    axi_ms.aw_valid <= axi_ms_i.aw_valid;
920	    axi_ms.w_data   <= axi_ms_i.w_data;
921	    axi_ms.w_strb   <= axi_ms_i.w_strb;
922	    axi_ms.w_valid  <= axi_ms_i.w_valid;
923	    axi_ms.b_ready  <= axi_ms_i.b_ready;
924	
925	    axi_sm_i.ar_ready <= axi_sm.ar_ready;
926	    axi_sm_i.r_id     <= toUslv(0, instance.id_width);
927	    axi_sm_i.r_data   <= axi_sm.r_data;
928	    axi_sm_i.r_resp   <= axi_sm.r_resp;
929	    axi_sm_i.r_last   <= '1';
930	    axi_sm_i.r_user   <= toUslv(0, instance.user_width);
931	    axi_sm_i.r_valid  <= axi_sm.r_valid;
932	    axi_sm_i.aw_ready <= axi_sm.aw_ready;
933	    axi_sm_i.w_ready  <= axi_sm.w_ready;
934	    axi_sm_i.b_id     <= toUslv(0, instance.id_width);
935	    axi_sm_i.b_resp   <= axi_sm.b_resp;
936	    axi_sm_i.b_user   <= toUslv(0, instance.user_width);
937	    axi_sm_i.b_valid  <= axi_sm.b_valid;
938	
939	    i_full_master : entity work.olo_test_axi_master_vc
940	        generic map (
941	            instance => instance
942	        )
943	        port map (
944	            clk      => clk,
945	            -- AXI MS
946	            axi_ms   => axi_ms_i,
947	            axi_sm   => axi_sm_i
948	        );
949	
950	end architecture;
