31	-- vunit: run_all_in_same_sim
32	entity olo_axi_lite_slave_tb is
33	    generic (
34	        AxiAddrWidth_g      : positive                          := 32;
35	        AxiDataWidth_g      : positive range 8 to positive'high := 16;
36	        runner_cfg          : string
37	    );
38	end entity;
39	
40	architecture sim of olo_axi_lite_slave_tb is
41	
42	    -----------------------------------------------------------------------------------------------
43	    -- AXI Definition
44	    -----------------------------------------------------------------------------------------------
45	    constant IdWidth_c   : integer := 0;
46	    constant AddrWidth_c : integer := AxiAddrWidth_g;
47	    constant UserWidth_c : integer := 0;
48	    constant DataWidth_c : integer := AxiDataWidth_g;
49	    constant ByteWidth_c : integer := DataWidth_c/8;
50	
51	    subtype IdRange_c   is natural range IdWidth_c-1 downto 0;
52	    subtype AddrRange_c is natural range AddrWidth_c-1 downto 0;
53	    subtype UserRange_c is natural range UserWidth_c-1 downto 0;
54	    subtype DataRange_c is natural range DataWidth_c-1 downto 0;
55	    subtype ByteRange_c is natural range ByteWidth_c-1 downto 0;
56	
57	    signal AxiMs : axi_ms_t (ar_id(IdRange_c), aw_id(IdRange_c),
58	                              ar_addr(AddrRange_c), aw_addr(AddrRange_c),
59	                              ar_user(UserRange_c), aw_user(UserRange_c), w_user(UserRange_c),
60	                              w_data(DataRange_c),
61	                              w_strb(ByteRange_c));
62	
63	    signal AxiSm : axi_sm_t (r_id(IdRange_c), b_id(IdRange_c),
64	                              r_user(UserRange_c), b_user(UserRange_c),
65	                              r_data(DataRange_c));
66	
67	    -----------------------------------------------------------------------------------------------
68	    -- Constants
69	    -----------------------------------------------------------------------------------------------
70	
71	    -----------------------------------------------------------------------------------------------
72	    -- TB Defnitions
73	    -----------------------------------------------------------------------------------------------
74	    constant Clk_Frequency_c : real := 100.0e6;
75	    constant Clk_Period_c    : time := (1 sec) / Clk_Frequency_c;
76	    -----------------------------------------------------------------------------------------------
77	    -- TB Defnitions
78	    -----------------------------------------------------------------------------------------------
79	
80	    -- *** Verification Compnents ***
81	    constant AxiMaster_c : olo_test_axi_master_t := new_olo_test_axi_master (
82	        data_width => DataWidth_c,
83	        addr_width => AddrWidth_c,
84	        id_width => IdWidth_c
85	    );
86	
87	    -----------------------------------------------------------------------------------------------
88	    -- Interface Signals
89	    -----------------------------------------------------------------------------------------------
90	    -- Control
91	    signal Clk : std_logic := '0';
92	    signal Rst : std_logic := '0';
93	
94	    -- Register Interface
95	    signal Rb_Addr    : std_logic_vector(AxiAddrWidth_g - 1 downto 0);
96	    signal Rb_Wr      : std_logic;
97	    signal Rb_ByteEna : std_logic_vector((AxiDataWidth_g/8) - 1 downto 0);
98	    signal Rb_WrData  : std_logic_vector(AxiDataWidth_g - 1 downto 0);
99	    signal Rb_Rd      : std_logic;
100	    signal Rb_RdData  : std_logic_vector(AxiDataWidth_g - 1 downto 0);
101	    signal Rb_RdValid : std_logic := '0';
102	
103	begin
104	
105	    -----------------------------------------------------------------------------------------------
106	    -- TB Control
107	    -----------------------------------------------------------------------------------------------
108	    test_runner_watchdog(runner, 1 ms);
109	
110	    p_control : process is
111	        variable Addr_v : unsigned(AxiAddrWidth_g - 1 downto 0);
112	        variable Data_v : unsigned(AxiDataWidth_g - 1 downto 0);
113	        variable Strb_v : std_logic_vector((AxiDataWidth_g/8) - 1 downto 0);
114	    begin
115	        test_runner_setup(runner, runner_cfg);
116	
117	        while test_suite loop
118	
119	            -- Reset
120	            wait until rising_edge(Clk);
121	            Rst <= '1';
122	            wait for 1 us;
123	            wait until rising_edge(Clk);
124	            Rst <= '0';
125	            wait until rising_edge(Clk);
126	
127	            -- check register reset values
128	            if run("RstValues") then
129	                check_equal(Rb_Wr, '0', "Reg_Wr reset value failed");
130	                check_equal(Rb_Rd, '0', "Reg_Rd reset value failed");
131	            end if;
132	
133	            -- Single write to registers
134	            if run("SingleWrite") then
